mapper.select:
SELECT c.id AS commentId, c.user_id AS userId, u.nickname, c.content, c.created_at AS createdAt FROM recipe_comments c JOIN users u ON c.user_id = u.id WHERE c.recipe_id = #{recipeId} AND c.deleted_at IS NULL
AND c.id < #{lastCommentId}
ORDER BY c.id DESC LIMIT #{size}

